// sr_methods.js — 200 questions (Maths Methods, Years 11-12)
const Q_SR_METHODS=[{"id": "srm111001", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Quadratics", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Find the roots of the quadratic equation x² − 5x + 6 = 0.", "options": ["x = 1 and x = 6", "x = 2 and x = 3", "x = -2 and x = -3", "x = 2 and x = -3"], "answer": 1, "exp": "Step 1: Factorise: x²−5x+6 = (x−2)(x−3). Step 2: Setting each factor to zero gives x=2 and x=3.", "hint": "Find two numbers that multiply to 6 and add to -5."}, {"id": "srm111002", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Quadratics", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "For the quadratic f(x) = x² − 4x + 7, what is the y-coordinate of the vertex (turning point)?", "options": ["1", "2", "3", "4"], "answer": 2, "exp": "Step 1: The x-coordinate of the vertex is -b/(2a) = 4/2 = 2. Step 2: f(2) = 4−8+7 = 3.", "hint": "Find the x-coordinate of the vertex first, then substitute back into f(x)."}, {"id": "srm111003", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Cubics", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Find all real roots of the cubic equation x³ + 2x² − x − 2 = 0.", "options": ["x = -2, -1, 1", "x = -2, 1, 2", "x = -1, 1, 2", "x = -2, -1, 2"], "answer": 0, "exp": "Step 1: Factorise: x³+2x²−x−2 = (x+2)(x+1)(x−1). Step 2: Setting each factor to zero gives x=-2, x=-1, x=1.", "hint": "Try factorising by grouping, or test small integer values to find a root, then factorise further."}, {"id": "srm111004", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Transformations", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "The graph of y = (x − 3)² + 2 is a transformation of y = x². What is the vertex of this transformed graph?", "options": ["(3, 2)", "(-3, 2)", "(3, -2)", "(-3, -2)"], "answer": 0, "exp": "In the form y=(x−h)²+k, the vertex is at (h,k). Here h=3 and k=2, giving a vertex of (3,2).", "hint": "Compare the equation to the standard transformed form y=(x−h)²+k."}, {"id": "srm111005", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Composite Functions", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "If f(x) = x + 3 and g(x) = x², what is g(f(x)) (the composite function), fully expanded?", "options": ["x² + 3", "x² + 6x + 9", "x² + 6", "x² + 9"], "answer": 1, "exp": "Step 1: g(f(x)) means substituting f(x) into g: g(x+3) = (x+3)². Step 2: Expand: (x+3)² = x²+6x+9.", "hint": "Substitute the entire expression for f(x) into every x in g(x), then expand."}, {"id": "srm111006", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Composite Functions", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Using f(x) = x + 3 and g(x) = x², what is g(f(2))?", "options": ["13", "19", "25", "28"], "answer": 2, "exp": "Step 1: f(2) = 2+3 = 5. Step 2: g(5) = 5² = 25.", "hint": "Work out f(2) first, then substitute that result into g(x)."}, {"id": "srm111007", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Inverse Functions", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "A linear function has the rule f(x) = 2x + 5. What is the rule for its inverse function, f⁻¹(x)?", "options": ["f⁻¹(x) = (x − 5)/2", "f⁻¹(x) = (x + 5)/2", "f⁻¹(x) = 2x − 5", "f⁻¹(x) = x/2 − 5"], "answer": 0, "exp": "Step 1: Write y=2x+5, then swap x and y: x=2y+5. Step 2: Solve for y: y=(x−5)/2.", "hint": "Swap x and y in the original equation, then solve for the new y."}, {"id": "srm111008", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Domain and Range", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "What is the domain of the function f(x) = √(x − 4)?", "options": ["all real numbers", "x ≥ 4", "x ≤ 4", "x ≠ 4"], "answer": 1, "exp": "Since the expression under a square root must be non-negative, x−4 ≥ 0, which gives x ≥ 4.", "hint": "Think about what values keep the expression under the square root non-negative."}, {"id": "srm111009", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Domain and Range", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "What is the range of the function f(x) = x² + 3?", "options": ["all real numbers", "y ≥ 0", "y ≥ 3", "y ≤ 3"], "answer": 2, "exp": "Since x² is always ≥ 0, the minimum value of x²+3 is 3 (when x=0), so the range is y ≥ 3.", "hint": "Think about the smallest possible value x² + 3 can take."}, {"id": "srm111010", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Transformations", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Which transformation describes moving the graph of y = x² to obtain the graph of y = x² − 5?", "options": ["a horizontal shift 5 units right", "a vertical shift 5 units down", "a vertical shift 5 units up", "a horizontal shift 5 units left"], "answer": 1, "exp": "Subtracting a constant from the function (y = x² − 5) shifts the entire graph down by that amount — a vertical shift of 5 units down.", "hint": "Think about what subtracting a constant from a function's output does to its graph."}, {"id": "srm111011", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Transformations", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Which transformation describes moving the graph of y = x² to obtain the graph of y = (x + 4)²?", "options": ["a horizontal shift 4 units right", "a horizontal shift 4 units left", "a vertical shift 4 units up", "a vertical shift 4 units down"], "answer": 1, "exp": "In the form y=(x−h)², a positive shift right uses (x−h). Since we have (x+4) = (x−(-4)), this represents h=-4, a horizontal shift 4 units LEFT.", "hint": "Remember that (x+4) can be rewritten as (x−(−4)), which shifts the graph in the opposite direction you might expect."}, {"id": "srm111012", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Quadratics", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "What is the discriminant of the quadratic equation 2x² + 3x − 5 = 0, and what does it indicate about the number of real solutions?", "options": ["49, indicating two distinct real solutions", "9, indicating two distinct real solutions", "-31, indicating no real solutions", "49, indicating one repeated solution"], "answer": 0, "exp": "Step 1: Discriminant = b²−4ac = 3²−4(2)(-5) = 9+40 = 49. Step 2: Since 49 is positive, there are two distinct real solutions.", "hint": "Calculate b²−4ac, then interpret whether the result is positive, zero, or negative."}, {"id": "srm111013", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Quadratics", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "For the function f(x) = 3(x − 1)² − 4, what is the axis of symmetry?", "options": ["x = -1", "x = 1", "x = -4", "x = 4"], "answer": 1, "exp": "In the form f(x)=a(x−h)²+k, the axis of symmetry is x=h. Here h=1, so the axis of symmetry is x=1.", "hint": "Compare the equation to the standard turning-point form to identify h directly."}, {"id": "srm111014", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Which best describes a 'one-to-one' function?", "options": ["a function where every output value corresponds to exactly one input value", "a function where some output values repeat for different inputs", "a function with no defined inverse", "a function that is always linear"], "answer": 0, "exp": "A one-to-one function has the property that every output value corresponds to exactly one input value, meaning no two different inputs produce the same output. This property is required for a function to have a valid inverse.", "hint": "Think about a function where you could always determine the unique input, just by knowing the output."}, {"id": "srm111015", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Inverse Functions", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Why does the function f(x) = x² (over all real numbers) NOT have an inverse function in the usual sense?", "options": ["x² has no real outputs at all", "x² is not one-to-one, since both x and -x produce the same output, so a unique inverse cannot be defined over all reals", "x² is already its own inverse", "this statement is false — x² always has an inverse"], "answer": 1, "exp": "Since both x and -x produce the same output under f(x)=x² (e.g. f(2)=f(-2)=4), the function is not one-to-one over all real numbers, so a unique inverse cannot be defined without restricting the domain.", "hint": "Think about whether you could always tell which original input was used, just from the output value."}, {"id": "srm111016", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Quadratics", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "What are the x-intercepts of the function f(x) = (x − 2)(x + 5)?", "options": ["x = 2 and x = 5", "x = -2 and x = 5", "x = 2 and x = -5", "x = -2 and x = -5"], "answer": 2, "exp": "Setting each factor to zero: x−2=0 gives x=2, and x+5=0 gives x=-5.", "hint": "Set each factor in the factorised form equal to zero and solve."}, {"id": "srm111017", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Cubics", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "A cubic function has the rule f(x) = x³ − 8. What is its only real x-intercept?", "options": ["x = 2", "x = -2", "x = 4", "x = 8"], "answer": 0, "exp": "Setting f(x)=0: x³=8, so x=2 (the cube root of 8). The other two solutions involve complex numbers, leaving x=2 as the only real x-intercept.", "hint": "Find the cube root of 8 to solve x³=8."}, {"id": "srm111018", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Which best describes the graph of an exponential function f(x) = 2ˣ?", "options": ["a straight line with constant gradient", "a parabola symmetric about the y-axis", "a curve that increases rapidly, with a horizontal asymptote at y=0 as x decreases", "a curve passing through the origin (0,0)"], "answer": 2, "exp": "An exponential function like 2ˣ increases rapidly for positive x, approaches (but never reaches) y=0 as x becomes very negative (a horizontal asymptote), and never passes through the origin (since 2⁰=1, not 0).", "hint": "Think about the characteristic shape of exponential growth, including its behaviour for very negative x values."}, {"id": "srm111019", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "For the exponential function f(x) = 2ˣ, what is f(3)?", "options": ["6", "8", "9", "16"], "answer": 1, "exp": "f(3) = 2³ = 8.", "hint": "Substitute x=3 into the exponential function and evaluate."}, {"id": "srm111020", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Which point does every exponential function of the form f(x) = aˣ (where a > 0) pass through, regardless of the value of a?", "options": ["(0, 0)", "(0, 1)", "(1, 0)", "(1, 1)"], "answer": 1, "exp": "Since any non-zero number raised to the power of 0 equals 1, f(0) = a⁰ = 1 for any valid base a, meaning every such exponential function passes through (0, 1).", "hint": "Think about what happens when x=0, regardless of the specific base used."}, {"id": "srm111021", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Rates of Change", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "What is the average rate of change of the function f(x) = x² between x=1 and x=4?", "options": ["3", "4", "5", "15"], "answer": 2, "exp": "Step 1: Average rate of change = (f(4)−f(1)) ÷ (4−1). Step 2: (16−1) ÷ 3 = 15÷3 = 5.", "hint": "Use the formula: (change in y) ÷ (change in x), evaluating the function at both endpoints."}, {"id": "srm111022", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Rates of Change", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Which best describes the average rate of change of a function between two points, geometrically?", "options": ["the y-coordinate of the function's vertex", "the gradient of the straight line (secant line) connecting the two points on the graph", "the function's value at the midpoint of the interval", "the function's maximum value over that interval"], "answer": 1, "exp": "The average rate of change between two points equals the gradient of the straight line (secant line) connecting those two points on the function's graph.", "hint": "Think about drawing a straight line directly between the two points — what does its steepness represent?"}, {"id": "srm111023", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Quadratics", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "A function has the rule f(x) = -2(x − 1)² + 8. Does this parabola open upward or downward, and what is its maximum or minimum value?", "options": ["opens upward, minimum value of 8", "opens downward, maximum value of 8", "opens upward, minimum value of -2", "opens downward, maximum value of -2"], "answer": 1, "exp": "Since the coefficient of the squared term is negative (-2), the parabola opens downward, meaning it has a maximum value at its vertex, which is 8 (at x=1).", "hint": "Check the sign of the leading coefficient to determine whether the parabola opens up or down, then identify the turning point value."}, {"id": "srm111024", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Which best describes a function's 'asymptote'?", "options": ["a point where the function crosses the x-axis", "a line that the graph of a function approaches but never actually touches or crosses (in many cases)", "the highest point on a function's graph", "a synonym for the function's domain"], "answer": 1, "exp": "An asymptote is a line that a function's graph approaches increasingly closely, but in many cases never actually touches or crosses, often as x or y becomes very large or very small.", "hint": "Think about a 'boundary' line that the graph gets closer and closer to, without quite reaching it."}, {"id": "srm111025", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M1", "q": "Which best describes how to determine whether a relation (a set of x and y pairs) represents a function?", "options": ["a relation is a function if every x-value is paired with exactly one y-value", "a relation is a function if every y-value is paired with exactly one x-value", "all relations are automatically functions", "a relation can never be tested for this property"], "answer": 0, "exp": "A relation represents a function if every x-value (input) is paired with exactly one y-value (output) — this is sometimes checked graphically using the 'vertical line test'.", "hint": "Think about whether a single input value could ever lead to two different possible outputs."}, {"id": "srm112001", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithms", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Evaluate: log₃(81)", "options": ["3", "4", "27", "81"], "answer": 1, "exp": "log₃(81) asks 'to what power must 3 be raised to get 81?' Since 3⁴=81, log₃(81)=4.", "hint": "Think about what power of 3 gives you 81."}, {"id": "srm112002", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithms", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Evaluate: log₁₀(0.01)", "options": ["-2", "-1", "1", "2"], "answer": 0, "exp": "log₁₀(0.01) asks 'to what power must 10 be raised to get 0.01?' Since 10⁻²=0.01, log₁₀(0.01)=-2.", "hint": "Remember that negative exponents create values less than 1."}, {"id": "srm112003", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential Equations", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Solve for x: 2ˣ = 16", "options": ["2", "3", "4", "8"], "answer": 2, "exp": "Since 2⁴=16, the solution is x=4.", "hint": "Express 16 as a power of 2, then compare exponents."}, {"id": "srm112004", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential Equations", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Solve for x: 3ˣ⁻¹ = 27", "options": ["2", "3", "4", "5"], "answer": 2, "exp": "Step 1: Express 27 as 3³. Step 2: Since the bases match, x−1=3, so x=4.", "hint": "Express both sides as powers of the same base, then equate the exponents."}, {"id": "srm112005", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithm Laws", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Using the logarithm law log(a)+log(b)=log(ab), simplify log₂(8)+log₂(4).", "options": ["log₂(12)", "log₂(32), which equals 5", "log₂(2)", "log₂(4)"], "answer": 1, "exp": "Step 1: log₂(8)+log₂(4) = log₂(8×4) = log₂(32). Step 2: Since 2⁵=32, this equals 5.", "hint": "Use the product law of logarithms to combine the two terms first."}, {"id": "srm112006", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Natural Logarithms", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Simplify: ln(e⁵)", "options": ["1", "5", "e", "e⁵"], "answer": 1, "exp": "Since ln and e^x are inverse functions, ln(e⁵)=5.", "hint": "Remember that the natural log and the exponential function 'undo' each other."}, {"id": "srm112007", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Natural Logarithms", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Simplify: e^(ln 7)", "options": ["1", "7", "e", "e⁷"], "answer": 1, "exp": "Since e^x and ln are inverse functions, e^(ln 7)=7.", "hint": "Remember that applying e^x to ln(a) simply returns a."}, {"id": "srm112008", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Which of these correctly describes the relationship between exponential and logarithmic functions?", "options": ["they are unrelated function types", "logarithmic functions are the inverse of exponential functions (with the same base)", "exponential functions are always linear", "logarithmic functions can only have a base of 10"], "answer": 1, "exp": "Logarithmic functions are the inverse of exponential functions with the same base — for example, log₂(x) is the inverse of 2ˣ.", "hint": "Think about which function 'undoes' the other, similar to how square roots undo squaring."}, {"id": "srm112009", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential Applications", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "A radioactive substance decays according to N(t) = 100 × 0.5^(t/5), where t is in years. After how many years will only 12.5 grams remain?", "options": ["10 years", "15 years", "20 years", "25 years"], "answer": 1, "exp": "Step 1: Solve 100×0.5^(t/5)=12.5, so 0.5^(t/5)=0.125. Step 2: Since 0.125=0.5³, t/5=3, giving t=15 years.", "hint": "Express 12.5/100 as a power of 0.5, then solve for the exponent."}, {"id": "srm112010", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "What is the y-intercept of the function f(x) = 3 × 2ˣ?", "options": ["0", "1", "2", "3"], "answer": 3, "exp": "At x=0: f(0) = 3 × 2⁰ = 3 × 1 = 3.", "hint": "Substitute x=0 into the function to find the y-intercept."}, {"id": "srm112011", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "What is the horizontal asymptote of the function f(x) = 2ˣ + 3?", "options": ["y = 0", "y = 1", "y = 2", "y = 3"], "answer": 3, "exp": "As x becomes very negative, 2ˣ approaches 0, so f(x) approaches 0+3=3. The horizontal asymptote is y=3.", "hint": "Think about what value the exponential term approaches as x becomes very negative, then add the constant."}, {"id": "srm112012", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Which best describes exponential decay, modelled by a function like f(x) = A×bˣ, where 0 < b < 1?", "options": ["the function increases without bound as x increases", "the function decreases toward (but never reaches) zero as x increases", "the function is always negative", "the function has no defined behaviour for large x"], "answer": 1, "exp": "When the base b is between 0 and 1, the function decreases over time, approaching (but never reaching) zero as x becomes very large — this is exponential decay.", "hint": "Think about repeatedly multiplying by a fraction less than 1, and what happens over many repetitions."}, {"id": "srm112013", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithmic Equations", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Solve for x: log₅(x) = 3", "options": ["15", "75", "125", "625"], "answer": 2, "exp": "log₅(x)=3 means 5³=x, so x=125.", "hint": "Rewrite the logarithmic equation in exponential form to solve for x."}, {"id": "srm112014", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithm Laws", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Using the logarithm law log(a)−log(b)=log(a/b), simplify log₃(54)−log₃(2).", "options": ["log₃(27), which equals 3", "log₃(52)", "log₃(108)", "log₃(56)"], "answer": 0, "exp": "Step 1: log₃(54)−log₃(2) = log₃(54/2) = log₃(27). Step 2: Since 3³=27, this equals 3.", "hint": "Use the quotient law of logarithms to combine the two terms first."}, {"id": "srm112015", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Which graph feature is shared by all exponential functions of the form f(x) = bˣ, where b > 1?", "options": ["a y-intercept at (0, 0)", "they are always decreasing", "they pass through (0, 1) and increase as x increases", "they have a vertical asymptote"], "answer": 2, "exp": "All exponential functions of this form pass through (0, 1) since b⁰=1, and increase as x increases (since b>1) — they do not have a vertical asymptote, but rather a horizontal one.", "hint": "Think about the one point every exponential function (regardless of base) always passes through."}, {"id": "srm112016", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithm Laws", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Using the power law of logarithms, log(aⁿ)=n×log(a), simplify log₂(8³).", "options": ["3", "9", "24", "512"], "answer": 1, "exp": "Step 1: log₂(8³) = 3×log₂(8). Step 2: log₂(8)=3, so 3×3=9.", "hint": "Bring the exponent down as a multiplier, then evaluate the simpler logarithm."}, {"id": "srm112017", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential Applications", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "A population grows according to P(t) = 500 × e^(0.05t), where t is in years. What is the population after 0 years (the initial population)?", "options": ["0", "1", "500", "525"], "answer": 2, "exp": "At t=0: P(0) = 500 × e⁰ = 500 × 1 = 500.", "hint": "Substitute t=0 into the function — remember that e⁰=1."}, {"id": "srm112018", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithm Laws", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Which of these is equivalent to logₐ(1), for any valid base a > 0, a ≠ 1?", "options": ["0", "1", "a", "undefined"], "answer": 0, "exp": "Since a⁰=1 for any valid base a, logₐ(1)=0 for any base.", "hint": "Think about what power any base must be raised to, in order to get 1."}, {"id": "srm112019", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithm Laws", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Which of these is equivalent to logₐ(a), for any valid base a > 0, a ≠ 1?", "options": ["0", "1", "a", "a²"], "answer": 1, "exp": "Since a¹=a, logₐ(a)=1 for any valid base.", "hint": "Think about what power the base must be raised to, in order to get itself."}, {"id": "srm112020", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential Equations", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Solve for x: 4^(2x) = 64", "options": ["1", "1.5", "2", "3"], "answer": 1, "exp": "Step 1: Express both sides with base 4: 4^(2x) = 4³ (since 64=4³). Step 2: 2x=3, so x=1.5.", "hint": "Express 64 as a power of 4, then equate the exponents."}, {"id": "srm112021", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithms", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Which best describes why the domain of a logarithmic function f(x) = log(x) is restricted to x > 0?", "options": ["there is no restriction on the domain of a logarithmic function", "logarithms of zero or negative numbers are undefined in the real number system", "logarithmic functions can only take whole number inputs", "this restriction only applies to base-10 logarithms"], "answer": 1, "exp": "Logarithms of zero or negative numbers are undefined within the real number system, since there is no real power you could raise a positive base to, to get zero or a negative result.", "hint": "Think about whether any real exponent could ever make a positive base produce zero or a negative number."}, {"id": "srm112022", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Exponential Applications", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "An investment grows according to A(t) = 5000 × (1.04)ᵗ. Approximately how many years will it take for the investment to double, using logarithms to solve 1.04ᵗ=2?", "options": ["about 12 years", "about 18 years", "about 24 years", "about 30 years"], "answer": 1, "exp": "Step 1: Take the logarithm of both sides: t×log(1.04)=log(2). Step 2: t = log(2)/log(1.04) ≈ 17.7, which rounds to approximately 18 years.", "hint": "Take the logarithm of both sides of the equation, then solve for t."}, {"id": "srm112023", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithms", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Which best describes the graph of f(x) = log₂(x), compared to f(x) = 2ˣ?", "options": ["they are identical graphs", "they are reflections of each other across the line y=x, since they are inverse functions", "they have no graphical relationship", "f(x)=log₂(x) is always above f(x)=2ˣ"], "answer": 1, "exp": "Since log₂(x) and 2ˣ are inverse functions of each other, their graphs are reflections of each other across the line y=x.", "hint": "Think about the general graphical relationship between any function and its inverse."}, {"id": "srm112024", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithmic Equations", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Solve for x: log(x) + log(5) = log(35)", "options": ["x = 5", "x = 7", "x = 30", "x = 175"], "answer": 1, "exp": "Step 1: Combine using the product law: log(5x)=log(35). Step 2: Since the logs are equal, 5x=35, giving x=7.", "hint": "Combine the left side into a single logarithm first, then equate the arguments."}, {"id": "srm112025", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Functions — Logarithm Applications", "difficulty": "hard", "style": "standard", "paper": "G11-M2", "q": "Which best describes a practical application of logarithmic scales, such as the Richter scale (earthquakes) or decibels (sound)?", "options": ["logarithmic scales have no real practical use", "they allow very large ranges of values to be represented and compared more manageably, since each unit represents a multiplicative (not additive) change", "logarithmic scales are only used in pure mathematics, never real-world measurement", "they only work for negative numbers"], "answer": 1, "exp": "Logarithmic scales allow very large ranges of values (such as earthquake intensity or sound pressure) to be represented and compared more manageably, since each unit increase represents a multiplicative change (e.g. each Richter magnitude is about 10 times more intense than the one before).", "hint": "Think about why measuring something across an enormous range of values might benefit from a scale where each step is a multiplication, not just an addition."}, {"id": "srm113001", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Differentiation Rules", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Using the power rule, find the derivative of f(x) = x⁴.", "options": ["4x³", "x³", "4x⁴", "x⁵/5"], "answer": 0, "exp": "Using the power rule (d/dx[xⁿ] = nxⁿ⁻¹): the derivative of x⁴ is 4x³.", "hint": "Multiply by the original exponent, then reduce the exponent by 1."}, {"id": "srm113002", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Differentiation Rules", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Find the derivative of f(x) = 3x³ − 2x² + 5x − 1.", "options": ["9x² − 4x + 5", "3x² − 2x + 5", "9x² − 4x", "9x³ − 4x² + 5x"], "answer": 0, "exp": "Differentiate each term separately: d/dx[3x³]=9x², d/dx[-2x²]=-4x, d/dx[5x]=5, d/dx[-1]=0. Combined: 9x²−4x+5.", "hint": "Apply the power rule to each term separately, remembering that the derivative of a constant is 0."}, {"id": "srm113003", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Evaluating Derivatives", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Using f'(x) = 9x² − 4x + 5, what is f'(2)?", "options": ["27", "29", "33", "37"], "answer": 2, "exp": "Step 1: Substitute x=2: 9(2)²−4(2)+5. Step 2: 9(4)−8+5 = 36−8+5 = 33.", "hint": "Substitute x=2 into the derivative expression and calculate carefully."}, {"id": "srm113004", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "What does the derivative f'(x) represent, geometrically, at a particular point on the graph of f(x)?", "options": ["the y-coordinate of that point", "the gradient (slope) of the tangent line to the curve at that point", "the area under the curve up to that point", "the x-intercept of the function"], "answer": 1, "exp": "The derivative f'(x) represents the gradient (slope) of the tangent line to the curve at a particular point — essentially, the instantaneous rate of change at that exact point.", "hint": "Think about the 'steepness' of the curve at one specific, exact point."}, {"id": "srm113005", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Evaluating Derivatives", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "For f(x) = x² − 3x + 1, what is the gradient of the curve at x = 4?", "options": ["3", "4", "5", "8"], "answer": 2, "exp": "Step 1: f'(x) = 2x − 3. Step 2: f'(4) = 2(4)−3 = 8−3 = 5.", "hint": "Find the derivative first, then substitute x=4."}, {"id": "srm113006", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Tangent Lines", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "What is the equation of the tangent line to f(x) = x³ at the point where x = 2?", "options": ["y = 8x − 8", "y = 12x − 16", "y = 12x − 8", "y = 8x − 16"], "answer": 1, "exp": "Step 1: f'(x)=3x², so the gradient at x=2 is f'(2)=12. Step 2: f(2)=8, so using y−8=12(x−2), this simplifies to y=12x−16.", "hint": "Find the gradient (using the derivative) and the y-value at x=2, then use the point-gradient form of a line."}, {"id": "srm113007", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Stationary Points", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "For the function g(x) = x³ − 3x, find the x-coordinates of the stationary points (where g'(x) = 0).", "options": ["x = 0 only", "x = -1 and x = 1", "x = -3 and x = 3", "x = -1, 0, and 1"], "answer": 1, "exp": "Step 1: g'(x) = 3x² − 3. Step 2: Setting g'(x)=0: 3x²=3, so x²=1, giving x=-1 or x=1.", "hint": "Find the derivative, set it equal to zero, and solve the resulting equation."}, {"id": "srm113008", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "What is a 'stationary point' of a function?", "options": ["a point where the function's value is zero", "a point where the derivative (gradient) equals zero", "a point where the function is undefined", "the y-intercept of the function"], "answer": 1, "exp": "A stationary point occurs where the derivative (gradient) of a function equals zero, meaning the tangent line at that point is horizontal.", "hint": "Think about a point on the curve where the tangent line would be perfectly flat (horizontal)."}, {"id": "srm113009", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Second Derivative Test", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "For g(x) = x³ − 3x, the second derivative is g''(x) = 6x. Using the second derivative test, what type of stationary point occurs at x = 1?", "options": ["a local maximum, since g''(1) < 0", "a local minimum, since g''(1) > 0", "a point of inflection, since g''(1) = 0", "this test cannot determine the type of stationary point here"], "answer": 1, "exp": "Step 1: g''(1) = 6(1) = 6, which is positive. Step 2: A positive second derivative at a stationary point indicates a local minimum.", "hint": "Substitute x=1 into the second derivative — a positive result indicates a minimum, a negative result indicates a maximum."}, {"id": "srm113010", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Second Derivative Test", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "For g(x) = x³ − 3x, what type of stationary point occurs at x = -1, given g''(x) = 6x?", "options": ["a local maximum, since g''(-1) < 0", "a local minimum, since g''(-1) > 0", "a point of inflection", "this cannot be determined"], "answer": 0, "exp": "Step 1: g''(-1) = 6(-1) = -6, which is negative. Step 2: A negative second derivative at a stationary point indicates a local maximum.", "hint": "Substitute x=-1 into the second derivative — a negative result indicates a maximum."}, {"id": "srm113011", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "What does it mean if f'(x) > 0 over a particular interval of a function's domain?", "options": ["the function is decreasing over that interval", "the function is increasing over that interval", "the function has a stationary point throughout that interval", "the function is undefined over that interval"], "answer": 1, "exp": "A positive derivative over an interval means the function's gradient is positive throughout, indicating the function is increasing over that interval.", "hint": "Think about what a positive gradient (slope) tells you about whether a function is rising or falling."}, {"id": "srm113012", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "What does it mean if f'(x) < 0 over a particular interval of a function's domain?", "options": ["the function is increasing over that interval", "the function is decreasing over that interval", "the function has no real values over that interval", "the function is constant over that interval"], "answer": 1, "exp": "A negative derivative over an interval means the function's gradient is negative throughout, indicating the function is decreasing over that interval.", "hint": "Think about what a negative gradient (slope) tells you about whether a function is rising or falling."}, {"id": "srm113013", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Differentiation Rules", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Find the derivative of f(x) = 5 (a constant function).", "options": ["0", "5", "5x", "undefined"], "answer": 0, "exp": "The derivative of any constant is always 0, since a constant function has a gradient of zero everywhere (it's a horizontal line).", "hint": "Think about the gradient of a perfectly flat, horizontal line."}, {"id": "srm113014", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Differentiation Rules", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Find the derivative of f(x) = 7x.", "options": ["0", "1", "7", "7x"], "answer": 2, "exp": "The derivative of a linear term ax is simply a, so the derivative of 7x is 7 (the constant gradient of this straight line).", "hint": "Think about the constant gradient of a straight line in the form y=mx."}, {"id": "srm113015", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "What is the relationship between the average rate of change of a function over an interval, and the derivative (instantaneous rate of change)?", "options": ["they are always exactly equal for any function", "the derivative at a specific point describes the instantaneous rate of change, while the average rate of change describes the overall change across an entire interval", "they have no mathematical relationship", "average rate of change can only be calculated using derivatives"], "answer": 1, "exp": "The derivative at a specific point gives the instantaneous rate of change at that exact point, while the average rate of change describes the overall change in the function's value across an entire interval (calculated as a secant line's gradient).", "hint": "Think about the difference between the rate of change at one single instant, versus the overall change across a whole interval."}, {"id": "srm113016", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Differentiation Rules", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "For f(x) = 2x³ − 6x² + 3, find f'(x).", "options": ["6x² − 12x", "2x² − 6x", "6x³ − 12x²", "6x² − 12x + 3"], "answer": 0, "exp": "Differentiate each term: d/dx[2x³]=6x², d/dx[-6x²]=-12x, d/dx[3]=0. Combined: 6x²−12x.", "hint": "Apply the power rule to each term, remembering the derivative of a constant is zero."}, {"id": "srm113017", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Stationary Points", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Using f'(x) = 6x² − 12x, find the x-coordinates of the stationary points of f(x) = 2x³ − 6x² + 3.", "options": ["x = 0 only", "x = 0 and x = 2", "x = -2 and x = 2", "x = 2 only"], "answer": 1, "exp": "Step 1: Set f'(x)=0: 6x²−12x=0. Step 2: Factorise: 6x(x−2)=0, giving x=0 or x=2.", "hint": "Factor out the common term first, then find the values that make each factor zero."}, {"id": "srm113018", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Which best describes a 'point of inflection' on a curve?", "options": ["a point where the function reaches its maximum value", "a point where the curve changes concavity (from curving upward to curving downward, or vice versa)", "a point where the function is undefined", "a synonym for a local minimum"], "answer": 1, "exp": "A point of inflection occurs where a curve changes concavity — switching from curving upward (concave up) to curving downward (concave down), or vice versa.", "hint": "Think about a point where the curve's overall 'bending direction' switches."}, {"id": "srm113019", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "A ball's height is modelled by h(t) = -5t² + 20t + 1, where t is in seconds. Using h'(t) = -10t + 20, at what time is the ball's instantaneous velocity (rate of change of height) equal to zero?", "options": ["t = 1 second", "t = 2 seconds", "t = 4 seconds", "t = 5 seconds"], "answer": 1, "exp": "Step 1: Set h'(t)=0: -10t+20=0. Step 2: Solving: t=2 seconds — this is when the ball reaches its maximum height (momentarily stationary before falling).", "hint": "Set the derivative (representing velocity) equal to zero and solve for t."}, {"id": "srm113020", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Applications", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Which best describes why understanding stationary points is useful for solving optimisation problems (such as maximising profit or minimising cost)?", "options": ["stationary points have no connection to optimisation", "stationary points often correspond to the maximum or minimum values of a function, which are exactly what optimisation problems are trying to find", "optimisation problems never involve calculus", "stationary points only exist for linear functions"], "answer": 1, "exp": "Stationary points often correspond to local maximum or minimum values of a function, which is exactly what optimisation problems (like maximising profit or minimising cost) are trying to identify.", "hint": "Think about how finding the 'highest' or 'lowest' point of a function relates directly to optimisation goals."}, {"id": "srm113021", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Stationary Points", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "For f(x) = x² + 4x + 7, find the x-coordinate of the single stationary point.", "options": ["x = -4", "x = -2", "x = 2", "x = 4"], "answer": 1, "exp": "Step 1: f'(x) = 2x+4. Step 2: Set f'(x)=0: 2x+4=0, giving x=-2.", "hint": "Find the derivative, set it to zero, and solve for x."}, {"id": "srm113022", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Which best describes the chain rule, used for differentiating composite functions?", "options": ["it states that the derivative of a sum equals the sum of the derivatives", "it allows differentiation of a composite function f(g(x)) by multiplying the derivative of the outer function by the derivative of the inner function", "it only applies to polynomial functions", "it states that the derivative of a constant function is always 1"], "answer": 1, "exp": "The chain rule allows differentiation of a composite function f(g(x)) by multiplying the derivative of the outer function (evaluated at g(x)) by the derivative of the inner function g'(x).", "hint": "Think about differentiating a function that is itself made up of one function nested inside another."}, {"id": "srm113023", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Differentiation Rules", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "For the function f(x) = (2x + 1)³, which method would be most appropriate for finding f'(x)?", "options": ["the power rule applied directly to (2x+1) without further consideration", "the chain rule, since this is a composite function (an outer cubing function applied to an inner linear function)", "this function cannot be differentiated", "the quotient rule"], "answer": 1, "exp": "Since (2x+1)³ is a composite function — a cubing function applied to the inner expression (2x+1) — the chain rule is the appropriate method for differentiating it.", "hint": "Think about whether this function is a simple polynomial, or a function nested inside another function."}, {"id": "srm113024", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "Which best describes why the derivative of a function is itself often another function (rather than just a single number)?", "options": ["the derivative is always a single fixed number for any function", "the derivative gives the gradient at EVERY point along the curve, and this gradient typically varies from point to point, requiring a function to describe it fully", "derivatives are only ever defined at a single specific point", "this statement is false — derivatives are never functions"], "answer": 1, "exp": "Since the gradient of a curve typically varies from point to point (except for straight lines), the derivative itself is generally a function describing the gradient at every possible x-value, not just a single fixed number.", "hint": "Think about whether the steepness of a curve like x² is the same at every single point, or whether it changes."}, {"id": "srm113025", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Calculus — Differentiation Rules", "difficulty": "hard", "style": "standard", "paper": "G11-M3", "q": "For f(x) = x⁵, find f'(x).", "options": ["5x⁴", "x⁴", "5x⁵", "x⁶/6"], "answer": 0, "exp": "Using the power rule: the derivative of x⁵ is 5x⁴.", "hint": "Multiply by the original exponent, then reduce the exponent by 1."}, {"id": "srm114001", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Conditional Probability", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "P(A and B) = 0.15 and P(B) = 0.3. What is P(A|B), the conditional probability of A given B?", "options": ["0.05", "0.30", "0.45", "0.50"], "answer": 3, "exp": "Step 1: P(A|B) = P(A and B) ÷ P(B). Step 2: 0.15 ÷ 0.3 = 0.50.", "hint": "Use the formula for conditional probability: P(A|B) = P(A and B) ÷ P(B)."}, {"id": "srm114002", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Independence", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Two events A and B have P(A)=0.4, P(B)=0.5, and P(A and B)=0.2. Are A and B independent?", "options": ["yes, since P(A)×P(B) = 0.4×0.5 = 0.2, which equals P(A and B)", "no, since the events share a common outcome", "yes, but only because P(A and B) is less than both P(A) and P(B)", "this cannot be determined from the given information"], "answer": 0, "exp": "Step 1: For independent events, P(A and B) should equal P(A)×P(B). Step 2: 0.4×0.5=0.2, which matches the given P(A and B)=0.2, confirming independence.", "hint": "Check whether P(A)×P(B) equals the given P(A and B)."}, {"id": "srm114003", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Without Replacement", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "A bag contains 5 red and 3 blue marbles. Two marbles are drawn WITHOUT replacement. What is the probability that both are red?", "options": ["5/14", "5/8", "15/56", "25/64"], "answer": 0, "exp": "Step 1: P(first red) = 5/8. Step 2: P(second red | first red) = 4/7. Step 3: Multiply: 5/8 × 4/7 = 20/56 = 5/14.", "hint": "Remember that after the first marble is removed, the totals for the second draw change."}, {"id": "srm114004", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Without Replacement", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Using the same bag (5 red, 3 blue), what is the probability of drawing NO red marbles in two draws without replacement (i.e. both blue)?", "options": ["3/28", "3/8", "9/64", "6/56"], "answer": 0, "exp": "Step 1: P(first blue) = 3/8. Step 2: P(second blue | first blue) = 2/7. Step 3: Multiply: 3/8 × 2/7 = 6/56 = 3/28.", "hint": "Calculate the probability of blue on the first draw, then blue again on the second draw (with updated totals)."}, {"id": "srm114005", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Complementary Events", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Using the same bag, what is the probability of drawing AT LEAST ONE red marble in two draws without replacement?", "options": ["3/28", "5/14", "25/28", "11/14"], "answer": 2, "exp": "Step 1: P(no red) = P(both blue) = 3/28 (from the previous question). Step 2: P(at least one red) = 1 − 3/28 = 25/28.", "hint": "Find the probability of the complementary event (no red at all), then subtract from 1."}, {"id": "srm114006", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Independence", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Which best describes 'independent events' in probability?", "options": ["events where the occurrence of one affects the probability of the other", "events where the occurrence of one has no effect on the probability of the other occurring", "events that can never occur together", "events that always occur together"], "answer": 1, "exp": "Independent events are events where the occurrence of one has no effect on the probability of the other occurring.", "hint": "Think about two events where knowing one happened tells you nothing new about whether the other will happen."}, {"id": "srm114007", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Mutually Exclusive Events", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Which best describes 'mutually exclusive' events?", "options": ["events that cannot both occur at the same time", "events that always occur together", "a synonym for independent events", "events where one event's probability depends on the other"], "answer": 0, "exp": "Mutually exclusive events cannot both occur at the same time — for example, rolling a 2 and rolling a 5 on a single die roll.", "hint": "Think about two outcomes where if one happens, the other definitely cannot happen at the same time."}, {"id": "srm114008", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Mutually Exclusive Events", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "For two mutually exclusive events A and B, what is P(A and B)?", "options": ["P(A) × P(B)", "0", "1", "P(A) + P(B)"], "answer": 1, "exp": "Since mutually exclusive events cannot both occur, P(A and B) = 0.", "hint": "Think about the probability of two events happening together, when they literally cannot both occur."}, {"id": "srm114009", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Conditional Probability (Bayes)", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "A medical test for a disease is 95% accurate, and 2% of the population has the disease. If a randomly selected person tests positive, why might the actual probability they have the disease still be relatively low, despite the test's high accuracy?", "options": ["this scenario is impossible — a 95% accurate test always gives a 95% chance of having the disease if positive", "because the disease is rare (only 2% of the population), the number of false positives among the healthy majority can still outnumber true positives among the few people with the disease", "accuracy has no connection to the probability of actually having a disease", "the test must be flawed if this occurs"], "answer": 1, "exp": "Because the disease is rare, even a small false-positive rate applied to the large healthy population can produce more false positives in absolute numbers than true positives from the small infected population, lowering the actual probability of disease given a positive result — a counterintuitive result often explained using Bayes' theorem.", "hint": "Think about applying a small error rate to a very large healthy group, versus a high accuracy rate to a very small infected group."}, {"id": "srm114010", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Independence", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "A spinner is spun twice, with each spin independent of the other. If P(landing on red) = 0.3 for each spin, what is P(red on both spins)?", "options": ["0.09", "0.30", "0.60", "0.91"], "answer": 0, "exp": "Step 1: For independent events, multiply: P(red) × P(red). Step 2: 0.3 × 0.3 = 0.09.", "hint": "Multiply the probability of each independent event together."}, {"id": "srm114011", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Tree Diagrams", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Using a tree diagram, a weighted coin has P(heads)=0.6. If flipped twice, what is the probability of getting exactly one head and one tail (in either order)?", "options": ["0.24", "0.36", "0.48", "0.60"], "answer": 2, "exp": "Step 1: P(head then tail) = 0.6×0.4=0.24. Step 2: P(tail then head) = 0.4×0.6=0.24. Step 3: Add both orders: 0.24+0.24=0.48.", "hint": "Consider both possible orders (head-then-tail, and tail-then-head), and add their probabilities."}, {"id": "srm114012", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Venn Diagrams", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Which best describes a 'Venn diagram' in the context of probability?", "options": ["a diagram with no connection to probability", "a visual representation showing the relationships (overlaps) between different events or sets", "a type of bar graph used only for categorical data", "a synonym for a tree diagram"], "answer": 1, "exp": "A Venn diagram visually represents the relationships between different events or sets, typically using overlapping circles to show shared outcomes.", "hint": "Think about a diagram using overlapping circles to show shared and distinct outcomes between groups."}, {"id": "srm114013", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Venn Diagrams", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "In a class of 30 students, 18 study French, 14 study Spanish, and 7 study both languages. How many students study NEITHER language?", "options": ["3", "5", "7", "9"], "answer": 1, "exp": "Step 1: Students studying at least one language = 18+14−7 = 25. Step 2: Students studying neither = 30−25 = 5.", "hint": "Find the number studying at least one language first, then subtract from the total."}, {"id": "srm114014", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Venn Diagrams", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Using the same class data, what is the probability that a randomly selected student studies French but NOT Spanish?", "options": ["11/30", "14/30", "18/30", "21/30"], "answer": 0, "exp": "Step 1: Students studying French only = total French − both = 18−7 = 11. Step 2: Probability = 11/30.", "hint": "Subtract the number studying both languages from the total number studying French."}, {"id": "srm114015", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Which formula correctly calculates P(A or B) for two events that are NOT mutually exclusive?", "options": ["P(A) + P(B)", "P(A) + P(B) − P(A and B)", "P(A) × P(B)", "P(A and B) − P(A) − P(B)"], "answer": 1, "exp": "For events that are not mutually exclusive, P(A or B) = P(A) + P(B) − P(A and B), to avoid double-counting the overlap.", "hint": "Think about why you'd need to subtract the overlap, to avoid counting it twice."}, {"id": "srm114016", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Conditional Probability", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Two dice are rolled. What is the probability that the sum is 7, given that the first die shows a 4?", "options": ["1/6", "1/4", "1/3", "1/2"], "answer": 0, "exp": "If the first die is 4, the second die must show 3 for the sum to be 7. There's a 1/6 probability of rolling a 3 on the second die.", "hint": "Think about what specific value the second die would need to show, given the first die is fixed at 4."}, {"id": "srm114017", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Concepts", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Which best describes a 'sample space' in probability?", "options": ["the average outcome of an experiment", "the set of all possible outcomes of an experiment", "a synonym for a single specific outcome", "a type of conditional probability"], "answer": 1, "exp": "A sample space is the set of all possible outcomes of a particular random experiment, such as {1,2,3,4,5,6} for rolling a single die.", "hint": "Think about the complete list of everything that could possibly happen in an experiment."}, {"id": "srm114018", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Complementary Events", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "A box contains 4 red, 3 green, and 3 yellow counters. A counter is drawn at random. What is P(not yellow)?", "options": ["3/10", "7/10", "4/10", "6/10"], "answer": 1, "exp": "Step 1: P(yellow) = 3/10. Step 2: P(not yellow) = 1 − 3/10 = 7/10.", "hint": "Find the probability of the event happening, then subtract from 1."}, {"id": "srm114019", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Two-Way Tables", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "In a two-way table, 50 students are categorised by whether they play sport and whether they play music. 20 play both, 15 play only sport, and 10 play only music. How many play neither?", "options": ["3", "5", "10", "15"], "answer": 1, "exp": "Step 1: Total playing at least one = 20+15+10 = 45. Step 2: Neither = 50−45 = 5.", "hint": "Add up everyone playing at least one activity, then subtract from the total."}, {"id": "srm114020", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Conditional Probability", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Which best describes why P(A|B) is generally NOT equal to P(B|A), unless P(A)=P(B)?", "options": ["these two probabilities always represent exactly the same calculation", "they represent different conditional relationships — the 'given' condition changes which probability and which total are being considered", "conditional probability is never directional", "this statement is incorrect — they are always equal"], "answer": 1, "exp": "P(A|B) and P(B|A) represent different conditional relationships, since the 'given' condition determines which event's probability is being restricted, and these generally produce different fractions unless the underlying probabilities of A and B happen to be equal.", "hint": "Think about how 'probability of rain given it's cloudy' is a genuinely different question from 'probability of cloudy given it's raining'."}, {"id": "srm114021", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Total Probability", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "A factory has two machines. Machine A produces 60% of items and has a 2% defect rate. Machine B produces 40% of items and has a 5% defect rate. What is the overall probability that a randomly selected item is defective?", "options": ["2.6%", "3.2%", "3.5%", "7%"], "answer": 1, "exp": "Step 1: P(defective) = P(A)×P(defective|A) + P(B)×P(defective|B). Step 2: (0.6×0.02)+(0.4×0.05) = 0.012+0.02 = 0.032, or 3.2%.", "hint": "Weight each machine's defect rate by the proportion of items it produces, then add the results."}, {"id": "srm114022", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Tree Diagrams", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Which best describes the purpose of a probability tree diagram for multi-stage events?", "options": ["it has no real practical use for probability calculations", "it visually organises all possible outcome sequences across multiple stages, with branch probabilities that can be multiplied along each path", "it can only be used for exactly two stages", "it replaces the need for any other probability calculation method"], "answer": 1, "exp": "A tree diagram visually organises all possible outcome sequences across multiple stages of an experiment, with the probability of each complete path found by multiplying the branch probabilities along that path.", "hint": "Think about how branching paths can represent each possible sequence of outcomes across several stages."}, {"id": "srm114023", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Conditional Probability", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "A survey shows 70% of people like coffee, and of those, 80% also like tea. What is the probability that a randomly selected person likes BOTH coffee and tea?", "options": ["0.14", "0.50", "0.56", "0.80"], "answer": 2, "exp": "Step 1: P(coffee and tea) = P(coffee) × P(tea|coffee). Step 2: 0.7 × 0.8 = 0.56.", "hint": "Multiply the probability of liking coffee by the conditional probability of also liking tea, given they like coffee."}, {"id": "srm114024", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Independence", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "Which best describes how the formula P(A and B) = P(A) × P(B|A) relates to the formula P(A and B) = P(A) × P(B), used specifically for independent events?", "options": ["these two formulas are always identical for any two events", "the general formula uses P(B|A), but for independent events specifically, P(B|A) simplifies to just P(B), since A has no effect on B's probability", "the general formula is only valid for mutually exclusive events", "there is no meaningful relationship between these two formulas"], "answer": 1, "exp": "The general formula for joint probability always uses the conditional P(B|A). For independent events specifically, knowing A occurred doesn't change B's probability, so P(B|A) simplifies to just P(B), giving the simpler independence formula.", "hint": "Think about why the conditional probability formula simplifies specifically when the two events don't affect each other."}, {"id": "srm114025", "state": "AU", "section": "sr_methods", "grade": "11", "topic": "Probability — Conditional Probability", "difficulty": "hard", "style": "standard", "paper": "G11-M4", "q": "A weather station reports P(rain today) = 0.4. Given that it rains today, P(rain tomorrow) = 0.7. What is P(rain on both days)?", "options": ["0.11", "0.28", "0.40", "0.70"], "answer": 1, "exp": "Step 1: P(rain both days) = P(rain today) × P(rain tomorrow | rain today). Step 2: 0.4 × 0.7 = 0.28.", "hint": "Multiply the probability of the first event by the conditional probability of the second event, given the first."}, {"id": "srm121001", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Chain Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the chain rule, find the derivative of f(x) = (3x + 2)⁴.", "options": ["4(3x+2)³", "12(3x+2)³", "4(3x+2)⁴", "12x(3x+2)³"], "answer": 1, "exp": "Step 1: Differentiate the outer function: 4(3x+2)³. Step 2: Multiply by the derivative of the inner function (3x+2), which is 3. Step 3: 4×3×(3x+2)³ = 12(3x+2)³.", "hint": "Differentiate the outer function first, then multiply by the derivative of the inner function."}, {"id": "srm121002", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Chain Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the chain rule, find the derivative of f(x) = (x² + 1)⁵.", "options": ["5(x²+1)⁴", "5x(x²+1)⁴", "10x(x²+1)⁴", "10(x²+1)⁴"], "answer": 2, "exp": "Step 1: Differentiate the outer function: 5(x²+1)⁴. Step 2: Multiply by the derivative of the inner function (x²+1), which is 2x. Step 3: 5×2x×(x²+1)⁴ = 10x(x²+1)⁴.", "hint": "Differentiate the outer function first, then multiply by the derivative of the inner function (2x)."}, {"id": "srm121003", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Chain Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the chain rule, find the derivative of f(x) = (5 − 2x)³.", "options": ["3(5−2x)²", "-6(5−2x)²", "6(5−2x)²", "-3(5−2x)²"], "answer": 1, "exp": "Step 1: Differentiate the outer function: 3(5−2x)². Step 2: Multiply by the derivative of the inner function (5−2x), which is -2. Step 3: 3×(-2)×(5−2x)² = -6(5−2x)².", "hint": "Be careful with the negative sign when finding the derivative of the inner function (5−2x)."}, {"id": "srm121004", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Product Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the product rule, find the derivative of f(x) = (2x + 1)(x² − 3).", "options": ["2x² − 6", "6x² + 2x − 6", "2x² + 2x − 6", "4x² + 2x − 3"], "answer": 1, "exp": "Step 1: Apply the product rule: f'(x) = (2)(x²−3) + (2x+1)(2x). Step 2: Expand: (2x²−6) + (4x²+2x) = 6x²+2x−6.", "hint": "Use the product rule: (derivative of first × second) + (first × derivative of second)."}, {"id": "srm121005", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Product Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the product rule, find the derivative of f(x) = x²(x + 4).", "options": ["2x² + 4x", "3x² + 8x", "x² + 8x", "3x² + 4x"], "answer": 1, "exp": "Step 1: Apply the product rule: f'(x) = (2x)(x+4) + (x²)(1). Step 2: Expand: (2x²+8x) + x² = 3x²+8x.", "hint": "Use the product rule: (derivative of first × second) + (first × derivative of second)."}, {"id": "srm121006", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Quotient Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the quotient rule, find the derivative of f(x) = (x² + 1)/(x − 2), then evaluate it at x = 3.", "options": ["-6", "-4", "2", "4"], "answer": 1, "exp": "Step 1: Apply the quotient rule: f'(x) = [(2x)(x−2) − (x²+1)(1)] / (x−2)². Step 2: This simplifies to (x²−4x−1)/(x−2)². Step 3: At x=3: (9−12−1)/1 = -4.", "hint": "Use the quotient rule formula, then substitute x=3 into the simplified result."}, {"id": "srm121007", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Quotient Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Which best describes the quotient rule formula for differentiating f(x) = u(x)/v(x)?", "options": ["f'(x) = u'(x)/v'(x)", "f'(x) = [u'(x)v(x) − u(x)v'(x)] / [v(x)]²", "f'(x) = u'(x)v(x) + u(x)v'(x)", "f'(x) = u'(x) − v'(x)"], "answer": 1, "exp": "The quotient rule states that for f(x)=u(x)/v(x), f'(x) = [u'(x)v(x) − u(x)v'(x)] / [v(x)]².", "hint": "Remember the quotient rule pattern: (derivative of top × bottom, minus top × derivative of bottom), all over the bottom squared."}, {"id": "srm121008", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Product Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Which best describes the product rule formula for differentiating f(x) = u(x)×v(x)?", "options": ["f'(x) = u'(x)×v'(x)", "f'(x) = u'(x)v(x) + u(x)v'(x)", "f'(x) = u'(x)v(x) − u(x)v'(x)", "f'(x) = u(x) + v(x)"], "answer": 1, "exp": "The product rule states that for f(x)=u(x)×v(x), f'(x) = u'(x)v(x) + u(x)v'(x).", "hint": "Remember the product rule pattern: (derivative of first × second) PLUS (first × derivative of second)."}, {"id": "srm121009", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Chain Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the chain rule, find the derivative of f(x) = √(x² + 4), which can be written as (x²+4)^(1/2).", "options": ["x/√(x²+4)", "1/(2√(x²+4))", "2x/√(x²+4)", "x²/√(x²+4)"], "answer": 0, "exp": "Step 1: Differentiate the outer function: (1/2)(x²+4)^(-1/2). Step 2: Multiply by the derivative of the inner function (2x): (1/2)(2x)(x²+4)^(-1/2) = x/√(x²+4).", "hint": "Rewrite the square root as a power of 1/2, then apply the chain rule."}, {"id": "srm121010", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Product Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the product rule, find the derivative of f(x) = (x + 3)²(x − 1).", "options": ["(x+3)(3x+5)", "2(x+3)(x−1) + (x+3)²", "3(x+3)²", "(x+3)(2x−1)"], "answer": 1, "exp": "Step 1: Apply the product rule, treating u=(x+3)² and v=(x−1): f'(x) = 2(x+3)(x−1) + (x+3)²(1). Step 2: This can be left in this factored form, or expanded further.", "hint": "Apply the product rule, remembering to use the chain rule to differentiate (x+3)² as u(x)."}, {"id": "srm121011", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Quotient Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "For f(x) = (x − 1)/(x + 1), what is f'(x), fully simplified?", "options": ["2/(x+1)²", "1/(x+1)²", "-2/(x+1)²", "2x/(x+1)²"], "answer": 0, "exp": "Step 1: Apply the quotient rule: f'(x) = [(1)(x+1) − (x−1)(1)] / (x+1)². Step 2: The numerator simplifies to (x+1−x+1) = 2. Step 3: f'(x) = 2/(x+1)².", "hint": "Apply the quotient rule, then simplify the numerator carefully — many terms will cancel."}, {"id": "srm121012", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Choosing a Method", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Which method would be most appropriate for differentiating f(x) = (2x+5)⁶?", "options": ["the chain rule", "the product rule", "the quotient rule", "none of these methods apply"], "answer": 0, "exp": "Since this is a composite function (a power function applied to an inner linear expression), the chain rule is the appropriate method.", "hint": "Think about whether this function is a single expression raised to a power, a product of two functions, or a quotient."}, {"id": "srm121013", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Choosing a Method", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Which method would be most appropriate for differentiating f(x) = x³ × (2x − 1)?", "options": ["the chain rule only", "the product rule", "the quotient rule", "this function cannot be differentiated"], "answer": 1, "exp": "Since this function is a product of two separate expressions (x³ and (2x−1)), the product rule is the appropriate method.", "hint": "Think about whether this function involves two separate factors being multiplied together."}, {"id": "srm121014", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Choosing a Method", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Which method would be most appropriate for differentiating f(x) = (x+1)/(x²+3)?", "options": ["the chain rule only", "the product rule", "the quotient rule", "none of these methods apply"], "answer": 2, "exp": "Since this function is one expression divided by another, the quotient rule is the appropriate method.", "hint": "Think about whether this function involves one expression being divided by another."}, {"id": "srm121015", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Chain Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "For f(x) = (4x − 3)⁵, evaluate f'(x) at x = 1.", "options": ["20", "60", "80", "100"], "answer": 0, "exp": "Step 1: f'(x) = 5(4x−3)⁴×4 = 20(4x−3)⁴. Step 2: At x=1: 20(4−3)⁴ = 20(1)⁴ = 20.", "hint": "Find the general derivative first, then substitute x=1 carefully."}, {"id": "srm121016", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Product Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the product rule, find f'(0) for f(x) = (x+2)(3x−5).", "options": ["-11", "-5", "1", "6"], "answer": 2, "exp": "Step 1: f'(x) = (1)(3x−5)+(x+2)(3). Step 2: At x=0: (1)(-5)+(2)(3) = -5+6 = 1.", "hint": "Apply the product rule, then substitute x=0 carefully."}, {"id": "srm121017", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Chain Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "For f(x) = (2x²+1)⁴, what is the derivative of the INNER function (2x²+1), used in applying the chain rule?", "options": ["2x", "4x", "4x+1", "2x²"], "answer": 1, "exp": "The derivative of the inner function 2x²+1 is 4x, which would be multiplied by the derivative of the outer power function when applying the chain rule.", "hint": "Differentiate just the expression inside the brackets."}, {"id": "srm121018", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Chain Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Which best explains why the chain rule is necessary when differentiating a composite function, rather than simply applying the power rule directly to the outer expression?", "options": ["the chain rule is never actually necessary", "the inner function's own rate of change must also be accounted for, since the outer function's input is changing at a rate determined by the inner function", "the power rule already accounts for composite functions automatically", "composite functions cannot be differentiated at all"], "answer": 1, "exp": "The chain rule is necessary because the inner function's own rate of change must be accounted for — the outer function's input (the inner function's output) is itself changing at a rate determined by the inner function's derivative.", "hint": "Think about why simply differentiating the 'outside' isn't enough, if what's 'inside' is also changing."}, {"id": "srm121019", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Combined Rules", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "For f(x) = x²(2x+1)³, which combination of rules would be required to differentiate this function?", "options": ["the chain rule only", "the product rule combined with the chain rule (since one factor, (2x+1)³, is itself a composite function)", "the quotient rule only", "no differentiation rules are required"], "answer": 1, "exp": "This function requires the product rule (since it's a product of x² and (2x+1)³) combined with the chain rule (since (2x+1)³ is itself a composite function requiring the chain rule to differentiate).", "hint": "Think about whether this function involves a product of two factors, AND whether one of those factors is itself a composite function."}, {"id": "srm121020", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Combined Rules", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "For f(x) = (3x − 1)²/(x + 2), which combination of rules would be required to differentiate this function?", "options": ["the quotient rule combined with the chain rule (since the numerator is a composite function)", "the product rule only", "no differentiation rules are required", "the chain rule only, with no need for the quotient rule"], "answer": 0, "exp": "This function requires the quotient rule (since it's one expression divided by another) combined with the chain rule (since the numerator (3x−1)² is itself a composite function).", "hint": "Think about whether this function is a quotient, AND whether part of it is itself a composite function."}, {"id": "srm121021", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Chain Rule", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the chain rule, find f'(x) for f(x) = 1/(x+3)², which can be written as (x+3)⁻².", "options": ["-2(x+3)⁻³", "2(x+3)⁻³", "-2(x+3)⁻¹", "(x+3)⁻³"], "answer": 0, "exp": "Step 1: Differentiate the outer function: -2(x+3)⁻³. Step 2: Multiply by the derivative of the inner function (x+3), which is 1. Step 3: Result: -2(x+3)⁻³.", "hint": "Rewrite as a negative power, then apply the chain rule as usual."}, {"id": "srm121022", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Simplifying Before Differentiating", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "For f(x) = (x² − 1)/(x + 1), which can be simplified by factorising the numerator first, what is the simplified form of f(x) (for x ≠ -1)?", "options": ["x + 1", "x − 1", "x² − 1", "1/(x+1)"], "answer": 1, "exp": "Step 1: Factorise the numerator: x²−1 = (x+1)(x−1). Step 2: Cancel the common factor (x+1): f(x) simplifies to x−1, for x≠-1.", "hint": "Try factorising the numerator as a difference of two squares, then look for a common factor to cancel."}, {"id": "srm121023", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Simplifying Before Differentiating", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Using the simplified form f(x) = x − 1 (from the previous question), what is f'(x)?", "options": ["0", "1", "x", "x−1"], "answer": 1, "exp": "The derivative of a simple linear function x−1 is just 1 (the coefficient of x).", "hint": "Think about the derivative of a simple linear expression."}, {"id": "srm121024", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Simplifying Before Differentiating", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "Which best describes why it can be beneficial to simplify an expression algebraically BEFORE differentiating, when possible?", "options": ["simplifying first never changes the difficulty of differentiating", "simplifying first can avoid the need for more complex rules (like the quotient rule), making the differentiation process more straightforward", "algebraic simplification is never compatible with calculus", "this approach always produces an incorrect derivative"], "answer": 1, "exp": "Simplifying an expression algebraically before differentiating, when possible, can avoid the need for more complex rules (like the quotient rule), making the overall differentiation process more straightforward.", "hint": "Think about how much simpler differentiating x−1 is, compared to using the quotient rule on the original unsimplified fraction."}, {"id": "srm121025", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Combined Rules", "difficulty": "hard", "style": "standard", "paper": "G12-M1", "q": "For f(x) = (x+4)³(x−2)², which rule(s) would be needed to find f'(x)?", "options": ["the product rule combined with the chain rule, since both factors are themselves composite functions", "the quotient rule only", "no rules are needed, since this is already in simplest form", "the chain rule only, applied to the entire product at once"], "answer": 0, "exp": "This function requires the product rule (since it's a product of two factors) combined with the chain rule (since both (x+4)³ and (x−2)² are themselves composite functions requiring the chain rule).", "hint": "Think about whether this function is a product of factors, AND whether each factor itself requires the chain rule."}, {"id": "srm122001", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Optimisation", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "A rectangle has a perimeter of 40 cm. Its area is given by A(x) = x(20−x), where x is one side length. Using calculus, find the value of x that maximises the area.", "options": ["5 cm", "10 cm", "15 cm", "20 cm"], "answer": 1, "exp": "Step 1: A(x) = 20x − x², so A'(x) = 20 − 2x. Step 2: Setting A'(x)=0: x=10.", "hint": "Find the derivative of the area function, set it equal to zero, and solve for x."}, {"id": "srm122002", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Optimisation", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using the result from the previous question (x=10), what is the maximum area of the rectangle?", "options": ["80 cm²", "90 cm²", "100 cm²", "110 cm²"], "answer": 2, "exp": "Step 1: Substitute x=10 into A(x)=x(20−x). Step 2: A(10) = 10×(20−10) = 10×10 = 100 cm².", "hint": "Substitute the optimal x-value back into the original area formula."}, {"id": "srm122003", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Optimisation", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "An open box is made from a square sheet of cardboard with side 12 cm, by cutting squares of side x from each corner and folding up the sides. The volume is V(x) = x(12−2x)². Using calculus, find the value of x (within the valid range 0<x<6) that maximises the volume.", "options": ["1 cm", "2 cm", "3 cm", "4 cm"], "answer": 1, "exp": "Step 1: Differentiate V(x) and set V'(x)=0. Step 2: This gives critical points at x=2 and x=6, but only x=2 lies within the valid range (0<x<6) for a real box.", "hint": "Find the derivative, solve for critical points, then check which one falls within the physically valid range."}, {"id": "srm122004", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Optimisation", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using the result from the previous question (x=2), what is the maximum volume of the box?", "options": ["100 cm³", "118 cm³", "128 cm³", "144 cm³"], "answer": 2, "exp": "Step 1: Substitute x=2 into V(x)=x(12−2x)². Step 2: V(2) = 2×(12−4)² = 2×64 = 128 cm³.", "hint": "Substitute the optimal x-value back into the original volume formula."}, {"id": "srm122005", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Curve Sketching", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "For the curve f(x) = x³ − 3x², find the intervals where the function is increasing.", "options": ["x < 0 and x > 2", "0 < x < 2", "x < 0 only", "x > 2 only"], "answer": 0, "exp": "Step 1: f'(x) = 3x²−6x = 3x(x−2). Step 2: f'(x) > 0 (increasing) when x<0 or x>2, since the parabola 3x(x-2) is positive outside its roots.", "hint": "Find the derivative, identify the stationary points, then test the sign of the derivative in each interval."}, {"id": "srm122006", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Curve Sketching", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "For the curve f(x) = x³ − 3x², find the interval where the function is decreasing.", "options": ["x < 0", "0 < x < 2", "x > 2", "there is no decreasing interval"], "answer": 1, "exp": "Step 1: f'(x) = 3x(x−2). Step 2: f'(x) < 0 (decreasing) between the roots, when 0 < x < 2.", "hint": "The derivative is negative between its two roots, since the parabola dips below zero there."}, {"id": "srm122007", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Curve Sketching", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "For f(x) = x³ − 3x², with stationary points at x=0 and x=2, which best describes the nature of each stationary point?", "options": ["x=0 is a local minimum, x=2 is a local maximum", "x=0 is a local maximum, x=2 is a local minimum", "both are local maxima", "both are local minima"], "answer": 1, "exp": "Since the function increases before x=0 and decreases after it, x=0 is a local maximum. Since the function decreases before x=2 and increases after it, x=2 is a local minimum.", "hint": "Think about whether the function is increasing or decreasing on either side of each stationary point."}, {"id": "srm122008", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Kinematics", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "An object's displacement is given by s(t) = t³ − 6t² + 9t (in metres, t in seconds). Find the velocity function v(t).", "options": ["3t² − 12t + 9", "3t² − 6t", "t² − 6t + 9", "3t² − 12t"], "answer": 0, "exp": "Velocity is the derivative of displacement: v(t) = s'(t) = 3t² − 12t + 9.", "hint": "Differentiate the displacement function to find velocity."}, {"id": "srm122009", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Kinematics", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using v(t) = 3t² − 12t + 9, what is the initial velocity, v(0)?", "options": ["0 m/s", "3 m/s", "9 m/s", "12 m/s"], "answer": 2, "exp": "Substituting t=0: v(0) = 3(0)−12(0)+9 = 9 m/s.", "hint": "Substitute t=0 into the velocity function."}, {"id": "srm122010", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Kinematics", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using v(t) = 3t² − 12t + 9, find the acceleration function a(t).", "options": ["6t − 12", "3t − 12", "6t", "t² − 12t"], "answer": 0, "exp": "Acceleration is the derivative of velocity: a(t) = v'(t) = 6t − 12.", "hint": "Differentiate the velocity function to find acceleration."}, {"id": "srm122011", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Kinematics", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using v(t) = 3t² − 12t + 9, find the time(s) when the object is momentarily at rest (v(t) = 0).", "options": ["t = 1 only", "t = 1 and t = 3", "t = 3 only", "t = 0 and t = 4"], "answer": 1, "exp": "Step 1: Set 3t²−12t+9=0. Step 2: Divide by 3: t²−4t+3=0. Step 3: Factorise: (t−1)(t−3)=0, giving t=1 or t=3.", "hint": "Set the velocity function equal to zero and solve the resulting quadratic equation."}, {"id": "srm122012", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Kinematics", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using a(t) = 6t − 12, at what time is the object's acceleration equal to zero?", "options": ["t = 1", "t = 2", "t = 3", "t = 4"], "answer": 1, "exp": "Setting 6t−12=0 gives t=2.", "hint": "Set the acceleration function equal to zero and solve for t."}, {"id": "srm122013", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Kinematics", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Which best describes the relationship between displacement, velocity, and acceleration in kinematics, in terms of calculus?", "options": ["they are all the same function, just labelled differently", "velocity is the derivative of displacement, and acceleration is the derivative of velocity (the second derivative of displacement)", "acceleration is the derivative of displacement directly, with no connection to velocity", "displacement is the derivative of velocity"], "answer": 1, "exp": "Velocity is the first derivative of displacement (rate of change of position), and acceleration is the derivative of velocity, making it the second derivative of displacement.", "hint": "Think about each quantity as describing the RATE OF CHANGE of the previous one."}, {"id": "srm122014", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Optimisation", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "A farmer wants to fence a rectangular paddock using 200 m of fencing, with one side against an existing wall (so fencing is only needed on three sides). If A(x) = x(200−2x) represents the area (x being the side perpendicular to the wall), find the value of x that maximises the area.", "options": ["40 m", "50 m", "60 m", "100 m"], "answer": 1, "exp": "Step 1: A(x) = 200x − 2x², so A'(x) = 200 − 4x. Step 2: Setting A'(x)=0: x=50.", "hint": "Find the derivative of the area function, set it to zero, and solve for x."}, {"id": "srm122015", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Optimisation", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using the result from the previous question (x=50), what is the maximum area of the paddock?", "options": ["4000 m²", "5000 m²", "6000 m²", "10000 m²"], "answer": 1, "exp": "Step 1: Substitute x=50 into A(x)=x(200−2x). Step 2: A(50) = 50×(200−100) = 50×100 = 5000 m².", "hint": "Substitute the optimal x-value back into the original area formula."}, {"id": "srm122016", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Curve Sketching", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Which best describes how to confirm that a stationary point found using calculus is actually a MAXIMUM, rather than a minimum or a point of inflection?", "options": ["all stationary points are automatically maxima", "check the sign of the second derivative at that point — a negative value confirms a local maximum, or examine the sign of the first derivative on either side", "stationary points cannot be classified at all", "check whether the x-coordinate is positive"], "answer": 1, "exp": "To confirm a maximum, check the sign of the second derivative at the stationary point (negative indicates a maximum), or examine the sign of the first derivative just before and after the point (changing from positive to negative confirms a maximum).", "hint": "Think about using either the second derivative test, or checking the gradient's sign just before and after the point."}, {"id": "srm122017", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Curve Sketching", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "For f(x) = x⁴ − 4x³, find f'(x).", "options": ["4x³ − 12x²", "4x³ − 4x²", "x³ − 4x²", "4x⁴ − 12x³"], "answer": 0, "exp": "Differentiate each term: d/dx[x⁴]=4x³, d/dx[-4x³]=-12x². Combined: 4x³−12x².", "hint": "Apply the power rule to each term separately."}, {"id": "srm122018", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Curve Sketching", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using f'(x) = 4x³ − 12x², find the stationary points of f(x) = x⁴ − 4x³.", "options": ["x = 0 only", "x = 0 and x = 3", "x = -3 and x = 3", "x = 3 only"], "answer": 1, "exp": "Step 1: Set 4x³−12x²=0. Step 2: Factorise: 4x²(x−3)=0, giving x=0 or x=3.", "hint": "Factor out the common term first, then find the values that make each factor zero."}, {"id": "srm122019", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Optimisation", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "A company's profit (in thousands of dollars) is modelled by P(x) = -2x² + 40x − 150, where x is the number of units produced (in hundreds). Using calculus, find the production level that maximises profit.", "options": ["x = 5", "x = 10", "x = 15", "x = 20"], "answer": 1, "exp": "Step 1: P'(x) = -4x + 40. Step 2: Setting P'(x)=0: x=10.", "hint": "Find the derivative of the profit function, set it to zero, and solve for x."}, {"id": "srm122020", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Optimisation", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using the result from the previous question (x=10), what is the maximum profit?", "options": ["$50,000", "$100,000", "$150,000", "$250,000"], "answer": 0, "exp": "Step 1: Substitute x=10 into P(x)=-2x²+40x−150. Step 2: P(10) = -200+400−150 = 50 (thousand dollars), or $50,000.", "hint": "Substitute the optimal x-value back into the original profit formula, remembering the units."}, {"id": "srm122021", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Kinematics", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "For the displacement function s(t) = t³ − 6t² + 9t, what is the displacement at t = 0?", "options": ["-9", "0", "6", "9"], "answer": 1, "exp": "Substituting t=0: s(0) = 0−0+0 = 0.", "hint": "Substitute t=0 into the displacement function."}, {"id": "srm122022", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Kinematics", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "For the displacement function s(t) = t³ − 6t² + 9t, what is the displacement at t = 1 (one of the times the object is momentarily at rest)?", "options": ["2", "4", "6", "9"], "answer": 1, "exp": "Substituting t=1: s(1) = 1−6+9 = 4.", "hint": "Substitute t=1 into the displacement function."}, {"id": "srm122023", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Optimisation", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Which best describes a practical limitation when applying calculus-based optimisation to real-world problems, such as the box-folding example?", "options": ["calculus-based optimisation has no real limitations", "solutions must be checked against real-world constraints (such as physically valid ranges for dimensions), since not every mathematical solution makes practical sense", "optimisation problems never have multiple critical points to consider", "calculus cannot be applied to any real-world problem"], "answer": 1, "exp": "Solutions found through calculus must be checked against real-world constraints, such as physically valid ranges for dimensions (e.g. a cut-out length can't be negative or larger than half the cardboard's side) — not every mathematically valid critical point makes practical sense in context.", "hint": "Think about why you might need to discard one of the mathematically valid solutions, based on the real-world context of the problem."}, {"id": "srm122024", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Curve Sketching", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "For f(x) = 2x³ − 9x² + 12x, find f'(x).", "options": ["6x² − 18x + 12", "2x² − 9x + 12", "6x² − 9x + 12", "6x³ − 18x² + 12x"], "answer": 0, "exp": "Differentiate each term: d/dx[2x³]=6x², d/dx[-9x²]=-18x, d/dx[12x]=12. Combined: 6x²−18x+12.", "hint": "Apply the power rule to each term separately."}, {"id": "srm122025", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Curve Sketching", "difficulty": "hard", "style": "standard", "paper": "G12-M2", "q": "Using f'(x) = 6x² − 18x + 12, find the stationary points of f(x) = 2x³ − 9x² + 12x.", "options": ["x = 1 and x = 2", "x = -1 and x = -2", "x = 0 and x = 3", "x = 1 only"], "answer": 0, "exp": "Step 1: Set 6x²−18x+12=0. Step 2: Divide by 6: x²−3x+2=0. Step 3: Factorise: (x−1)(x−2)=0, giving x=1 or x=2.", "hint": "Simplify the equation by dividing through by the common factor, then factorise."}, {"id": "srm123001", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Antiderivatives", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Find the antiderivative of f(x) = x³.", "options": ["x⁴/4 + c", "x⁴ + c", "4x³ + c", "x²/2 + c"], "answer": 0, "exp": "Using the reverse power rule: ∫xⁿ dx = xⁿ⁺¹/(n+1) + c. For n=3: x⁴/4 + c.", "hint": "Increase the exponent by 1, then divide by the new exponent."}, {"id": "srm123002", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Antiderivatives", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Find the antiderivative of f(x) = 4x³ − 6x.", "options": ["x⁴ − 3x² + c", "4x⁴ − 6x² + c", "x⁴ − 6x² + c", "x⁴/4 − 3x² + c"], "answer": 0, "exp": "Integrate each term separately: ∫4x³dx = x⁴, ∫-6x dx = -3x². Combined: x⁴ − 3x² + c.", "hint": "Apply the reverse power rule to each term separately, remembering to add the constant of integration."}, {"id": "srm123003", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Definite Integrals", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Evaluate the definite integral: ∫₀³ x² dx", "options": ["3", "6", "9", "27"], "answer": 2, "exp": "Step 1: The antiderivative of x² is x³/3. Step 2: Evaluate from 0 to 3: (3³/3) − (0³/3) = 9 − 0 = 9.", "hint": "Find the antiderivative, then substitute the upper and lower limits and subtract."}, {"id": "srm123004", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Definite Integrals", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Evaluate the definite integral: ∫₁⁴ (2x + 1) dx", "options": ["9", "15", "18", "21"], "answer": 2, "exp": "Step 1: The antiderivative of 2x+1 is x²+x. Step 2: Evaluate from 1 to 4: (16+4) − (1+1) = 20 − 2 = 18.", "hint": "Find the antiderivative, then substitute the upper and lower limits and subtract."}, {"id": "srm123005", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Which best describes what a definite integral ∫ₐᵇ f(x) dx represents, geometrically (when f(x) ≥ 0 over [a,b])?", "options": ["the gradient of f(x) at x=a", "the area enclosed between the curve f(x), the x-axis, and the vertical lines x=a and x=b", "the y-intercept of f(x)", "the average value of f(x) over the entire domain"], "answer": 1, "exp": "When f(x) ≥ 0 over the interval [a,b], the definite integral represents the area enclosed between the curve, the x-axis, and the vertical boundary lines x=a and x=b.", "hint": "Think about the geometric region being measured between a curve and the x-axis, within specific boundaries."}, {"id": "srm123006", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Area Under a Curve", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Find the area under the curve f(x) = x² between x=0 and x=2.", "options": ["2/3", "4/3", "8/3", "4"], "answer": 2, "exp": "Step 1: ∫₀² x² dx = [x³/3] from 0 to 2. Step 2: (8/3) − 0 = 8/3.", "hint": "Find the antiderivative, then evaluate between the given limits."}, {"id": "srm123007", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Definite Integrals", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "For the function f(x) = x² − 4, which lies below the x-axis between x=0 and x=2, what is the value of ∫₀² (x²−4) dx?", "options": ["-16/3", "-8/3", "8/3", "16/3"], "answer": 0, "exp": "Step 1: ∫₀² (x²−4) dx = [x³/3 − 4x] from 0 to 2. Step 2: (8/3−8) − 0 = -16/3.", "hint": "Evaluate the integral directly — a negative result occurs when the curve lies below the x-axis over this interval."}, {"id": "srm123008", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Area Under a Curve", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Using the result from the previous question, what is the actual AREA (a positive quantity) between the curve f(x)=x²−4 and the x-axis from x=0 to x=2?", "options": ["8/3", "16/3", "-16/3", "32/3"], "answer": 1, "exp": "Since the curve lies below the x-axis here, the integral gives a negative value (-16/3), but the actual area (a positive geometric quantity) is the absolute value: 16/3.", "hint": "Since area is always a positive quantity, take the absolute value of a negative integral result."}, {"id": "srm123009", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Area Under a Curve", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Why must you take the absolute value of a definite integral's result when the curve lies BELOW the x-axis, in order to find the actual geometric area?", "options": ["definite integrals can never be negative", "a definite integral calculates a signed value, where regions below the x-axis contribute negatively, but area itself is always a positive quantity", "this rule only applies to even functions", "absolute value has no real connection to definite integrals"], "answer": 1, "exp": "A definite integral calculates a signed value, where regions below the x-axis contribute negatively to the total. Since geometric area is always considered a positive quantity, the absolute value must be taken when the curve dips below the x-axis.", "hint": "Think about the difference between a 'signed' mathematical result and a 'geometric' area, which is always positive."}, {"id": "srm123010", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Area Between Curves", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Find the points of intersection between the line y = x + 2 and the curve y = x².", "options": ["x = -1 and x = 2", "x = 1 and x = -2", "x = -2 and x = -1", "x = 1 and x = 2"], "answer": 0, "exp": "Step 1: Set x+2 = x², giving x²−x−2=0. Step 2: Factorise: (x−2)(x+1)=0, giving x=2 or x=-1.", "hint": "Set the two expressions equal to each other and solve the resulting quadratic equation."}, {"id": "srm123011", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Area Between Curves", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Using the intersection points x=-1 and x=2, find the area between the curves y=x+2 and y=x².", "options": ["9/2", "11/2", "13/2", "15/2"], "answer": 0, "exp": "Step 1: Area = ∫₋₁² [(x+2)−x²] dx. Step 2: This evaluates to 9/2.", "hint": "Integrate the difference between the upper curve and the lower curve, between the intersection points."}, {"id": "srm123012", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Area Between Curves", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Which best describes the correct setup for finding the area between two curves, f(x) and g(x), where f(x) ≥ g(x) over the interval [a,b]?", "options": ["∫ₐᵇ f(x) dx only, ignoring g(x) entirely", "∫ₐᵇ [f(x) − g(x)] dx, integrating the difference between the upper and lower curves", "∫ₐᵇ [f(x) + g(x)] dx", "∫ₐᵇ f(x)×g(x) dx"], "answer": 1, "exp": "The area between two curves is found by integrating the difference between the upper curve and the lower curve, ∫ₐᵇ [f(x)−g(x)] dx, over the interval where f(x) ≥ g(x).", "hint": "Think about subtracting the lower boundary from the upper boundary, then integrating that difference."}, {"id": "srm123013", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Antiderivatives", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Find the antiderivative of f(x) = 6x² + 4x − 3.", "options": ["2x³ + 2x² − 3x + c", "6x³ + 4x² − 3x + c", "2x³ + 2x² + c", "12x + 4 + c"], "answer": 0, "exp": "Integrate each term: ∫6x²dx=2x³, ∫4x dx=2x², ∫-3 dx=-3x. Combined: 2x³+2x²−3x+c.", "hint": "Apply the reverse power rule to each term separately."}, {"id": "srm123014", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Why is a constant of integration (+c) included when finding an indefinite integral (antiderivative), but NOT when evaluating a definite integral?", "options": ["the constant of integration is never actually necessary", "for an indefinite integral, the constant accounts for the fact that many functions share the same derivative; for a definite integral, the constant cancels out when subtracting the two boundary values", "definite integrals always equal zero, making the constant irrelevant", "this is simply a notational convention with no mathematical reason"], "answer": 1, "exp": "For an indefinite integral, the constant (+c) accounts for the fact that many different functions (differing only by a constant) share the same derivative. For a definite integral, when evaluating F(b)−F(a), any constant c would cancel out, since it appears in both F(b) and F(a).", "hint": "Think about why a constant added to a function disappears when you subtract two values of that same function."}, {"id": "srm123015", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Definite Integrals", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Evaluate the definite integral: ∫₂⁵ 3 dx (integrating a constant function)", "options": ["3", "6", "9", "15"], "answer": 2, "exp": "Step 1: The antiderivative of the constant 3 is 3x. Step 2: Evaluate from 2 to 5: (15)−(6) = 9.", "hint": "Remember that integrating a constant c gives cx; then evaluate between the limits."}, {"id": "srm123016", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Which best describes the Fundamental Theorem of Calculus, in simple terms?", "options": ["it states that derivatives and integrals are completely unrelated operations", "it establishes that integration and differentiation are inverse processes, connecting the concept of accumulated area to the antiderivative", "it only applies to linear functions", "it states that all integrals equal zero"], "answer": 1, "exp": "The Fundamental Theorem of Calculus establishes that integration and differentiation are inverse processes, connecting the concept of accumulated area (the definite integral) to the antiderivative of a function.", "hint": "Think about how this theorem connects the two major branches of calculus: differentiation and integration."}, {"id": "srm123017", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Applications", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "A particle's velocity is given by v(t) = 6t − 12 (m/s). Find the displacement function s(t), given that s(0) = 5.", "options": ["s(t) = 3t² − 12t + 5", "s(t) = 3t² − 12t", "s(t) = 6t² − 12t + 5", "s(t) = 3t² − 6t + 5"], "answer": 0, "exp": "Step 1: Integrate v(t): s(t) = 3t² − 12t + c. Step 2: Use s(0)=5 to find c: 0−0+c=5, so c=5. Step 3: s(t) = 3t² − 12t + 5.", "hint": "Integrate the velocity function to get a general displacement function (with a constant), then use the given initial condition to find that constant."}, {"id": "srm123018", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Antiderivatives", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Find ∫(x³ + 2x) dx.", "options": ["x⁴/4 + x² + c", "x⁴ + x² + c", "x⁴/4 + 2x² + c", "3x² + 2 + c"], "answer": 0, "exp": "Integrate each term: ∫x³dx=x⁴/4, ∫2x dx=x². Combined: x⁴/4+x²+c.", "hint": "Apply the reverse power rule to each term separately."}, {"id": "srm123019", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Definite Integrals", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Evaluate ∫₀² (x³ − x) dx.", "options": ["2", "3", "4", "6"], "answer": 0, "exp": "Step 1: Antiderivative is x⁴/4 − x²/2. Step 2: Evaluate from 0 to 2: (16/4−4/2) − 0 = (4−2) = 2.", "hint": "Find the antiderivative, then substitute the upper and lower limits and subtract."}, {"id": "srm123020", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Which best describes why finding the exact area under a curve (rather than approximating it with rectangles) requires the concept of a limit, leading to the definite integral?", "options": ["limits have no real connection to area under a curve", "as the number of approximating rectangles increases toward infinity (and their width approaches zero), the sum of their areas approaches the exact area under the curve — this limiting process defines the definite integral", "approximating with rectangles always gives the exact answer immediately", "this concept only applies to straight-line functions"], "answer": 1, "exp": "As the number of approximating rectangles increases toward infinity (with their width approaching zero), the sum of their areas approaches the exact area under the curve — this limiting process is precisely what defines the definite integral.", "hint": "Think about how using more and more, increasingly thin rectangles would give a more and more accurate area estimate."}, {"id": "srm123021", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Area Under a Curve", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Find the area enclosed between the curve y = 4 − x² and the x-axis, between its two x-intercepts.", "options": ["16/3", "32/3", "8", "16"], "answer": 1, "exp": "Step 1: x-intercepts occur where 4−x²=0, giving x=-2 and x=2. Step 2: Area = ∫₋₂² (4−x²) dx = 32/3.", "hint": "Find the x-intercepts first to determine the limits of integration, then evaluate the definite integral."}, {"id": "srm123022", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Applications", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Which best describes a practical application of definite integrals beyond finding area, such as in physics or economics?", "options": ["definite integrals have no practical applications beyond pure mathematics", "definite integrals can calculate total accumulated quantities, such as total distance travelled (from a velocity function) or total cost (from a marginal cost function)", "definite integrals can only ever be used to find area under a curve", "definite integrals are purely a theoretical concept with no real applications"], "answer": 1, "exp": "Definite integrals can calculate total accumulated quantities from a rate function — such as total distance travelled (integrating velocity over time) or total cost (integrating a marginal cost function) — extending well beyond simply finding area under a curve.", "hint": "Think about how integrating any 'rate' function over an interval gives you the TOTAL accumulated amount over that interval."}, {"id": "srm123023", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Definite Integrals", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Evaluate ∫₁³ (3x² − 2x) dx.", "options": ["18", "20", "22", "24"], "answer": 0, "exp": "Step 1: Antiderivative is x³−x². Step 2: Evaluate from 1 to 3: (27−9) − (1−1) = 18 − 0 = 18.", "hint": "Find the antiderivative, then substitute the upper and lower limits and subtract."}, {"id": "srm123024", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Applications", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Which best describes how integration can be used to find the TOTAL distance travelled by an object, when its velocity changes direction (becomes negative) during the time interval?", "options": ["simply integrate the velocity function directly over the whole interval, with no further adjustment needed", "the interval must be split where velocity changes sign, taking the absolute value of each integral piece (representing distance), and then summing these — since total distance, unlike displacement, cannot decrease", "total distance can never be calculated using integration", "velocity must always be positive for integration to apply at all"], "answer": 1, "exp": "To find total distance (as opposed to displacement), the interval must be split at any point where velocity changes sign, with the absolute value taken of each resulting integral piece, then summed — since total distance accumulates regardless of direction, unlike displacement, which can decrease when motion reverses.", "hint": "Think about the difference between displacement (which can decrease if you go backward) and total distance travelled (which only ever increases, even moving backward)."}, {"id": "srm123025", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Calculus — Antiderivatives", "difficulty": "hard", "style": "standard", "paper": "G12-M3", "q": "Find the antiderivative of f(x) = 5.", "options": ["5x + c", "5 + c", "x + c", "5x² + c"], "answer": 0, "exp": "The antiderivative of a constant c is cx, so the antiderivative of 5 is 5x + c.", "hint": "Think about what function, when differentiated, gives back the constant 5."}, {"id": "srm124001", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Binomial Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "A binomial random variable X has n=10 trials and probability of success p=0.3. What is the expected value, E(X)?", "options": ["0.3", "3", "7", "10"], "answer": 1, "exp": "For a binomial distribution, E(X) = n×p. Step: 10×0.3 = 3.", "hint": "Use the formula E(X) = n × p for a binomial distribution."}, {"id": "srm124002", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Binomial Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Using the same binomial distribution (n=10, p=0.3), what is the variance, Var(X)?", "options": ["2.1", "3.0", "6.3", "7.0"], "answer": 0, "exp": "For a binomial distribution, Var(X) = n×p×(1−p). Step: 10×0.3×0.7 = 2.1.", "hint": "Use the formula Var(X) = n × p × (1−p)."}, {"id": "srm124003", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Binomial Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "For a binomial distribution with n=10 and p=0.3, what is P(X=3), to 4 decimal places? (Use the formula P(X=k) = C(n,k)×p^k×(1−p)^(n−k).)", "options": ["0.0900", "0.2001", "0.2668", "0.3000"], "answer": 2, "exp": "Step 1: C(10,3) = 120. Step 2: P(X=3) = 120 × (0.3)³ × (0.7)⁷ ≈ 0.2668.", "hint": "Use the binomial probability formula, calculating the combination, then the probability terms."}, {"id": "srm124004", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Binomial Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Which conditions must be satisfied for a random variable to follow a binomial distribution?", "options": ["a fixed number of trials, two possible outcomes per trial, constant probability of success, and independent trials", "an infinite number of trials with varying probabilities", "exactly two trials with any number of possible outcomes", "continuous data measured over an interval"], "answer": 0, "exp": "A binomial distribution requires: a fixed number of trials, exactly two possible outcomes per trial (success/failure), a constant probability of success across trials, and independence between trials.", "hint": "Think about the specific conditions describing a fixed number of independent yes/no trials."}, {"id": "srm124005", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Composite Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "If f(x) = 2x + 3 and g(x) = x² − 1, what is f(g(x))?", "options": ["2x² + 1", "2x² + 5", "2x² − 1", "x² + 2"], "answer": 0, "exp": "Step 1: f(g(x)) means substituting g(x) into f: f(x²−1) = 2(x²−1)+3. Step 2: Simplify: 2x²−2+3 = 2x²+1.", "hint": "Substitute the entire expression for g(x) into every x in f(x), then simplify."}, {"id": "srm124006", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Composite Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Using f(x) = 2x + 3 and g(x) = x² − 1, what is g(f(x))?", "options": ["4x² + 12x + 8", "2x² + 5", "4x² + 9", "2x² + 12x + 8"], "answer": 0, "exp": "Step 1: g(f(x)) means substituting f(x) into g: g(2x+3) = (2x+3)²−1. Step 2: Expand: 4x²+12x+9−1 = 4x²+12x+8.", "hint": "Substitute the entire expression for f(x) into every x in g(x), then expand and simplify."}, {"id": "srm124007", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Inverse Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "For f(x) = 2x + 3, what is the rule for the inverse function f⁻¹(x)?", "options": ["f⁻¹(x) = (x−3)/2", "f⁻¹(x) = (x+3)/2", "f⁻¹(x) = 2x−3", "f⁻¹(x) = x/2+3"], "answer": 0, "exp": "Step 1: Write y=2x+3, swap x and y: x=2y+3. Step 2: Solve for y: y=(x−3)/2.", "hint": "Swap x and y in the original equation, then solve for the new y."}, {"id": "srm124008", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Inverse Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Which best describes the relationship between a function f(x) and its inverse f⁻¹(x), in terms of composition?", "options": ["f(f⁻¹(x)) and f⁻¹(f(x)) both equal x, for values within the appropriate domain", "f(f⁻¹(x)) always equals 0", "composing a function with its inverse always gives 1", "there is no defined relationship between a function and its inverse"], "answer": 0, "exp": "A defining property of inverse functions is that composing them in either order returns the original input: f(f⁻¹(x))=x and f⁻¹(f(x))=x, within the appropriate domain.", "hint": "Think about what it means for two functions to perfectly 'undo' each other."}, {"id": "srm124009", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Concepts", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "For a probability distribution to be valid, which of these conditions must P(X=x) satisfy for all possible values of x?", "options": ["0 ≤ P(X=x) ≤ 1, and the sum of all probabilities equals 1", "P(X=x) can be any real number", "P(X=x) must always equal exactly 0.5", "the sum of all probabilities must equal 0"], "answer": 0, "exp": "For a valid probability distribution, every individual probability must satisfy 0 ≤ P(X=x) ≤ 1, and the sum of all probabilities across every possible outcome must equal exactly 1.", "hint": "Think about the basic requirements for any probability value, plus the requirement for the total across all outcomes."}, {"id": "srm124010", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Binomial Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "A fair coin is flipped 8 times. Using the binomial distribution with n=8 and p=0.5, what is the expected number of heads, E(X)?", "options": ["2", "4", "6", "8"], "answer": 1, "exp": "E(X) = n×p = 8×0.5 = 4.", "hint": "Use the formula E(X) = n × p."}, {"id": "srm124011", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Binomial Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "For the same coin-flipping scenario (n=8, p=0.5), what is the variance, Var(X)?", "options": ["1", "2", "3", "4"], "answer": 1, "exp": "Var(X) = n×p×(1−p) = 8×0.5×0.5 = 2.", "hint": "Use the formula Var(X) = n × p × (1−p)."}, {"id": "srm124012", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Inverse Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Which best describes why the function f(x) = x² must have its domain restricted (e.g. to x ≥ 0) before a valid inverse function can be defined?", "options": ["restricting the domain has no effect on whether an inverse exists", "without restriction, f(x)=x² is not one-to-one (since f(2)=f(-2)=4), so a unique inverse cannot be defined without first restricting the domain", "f(x)=x² always has a valid inverse over all real numbers with no restriction needed", "inverse functions are never affected by domain restrictions"], "answer": 1, "exp": "Without restriction, f(x)=x² is not one-to-one (since both x=2 and x=-2 produce the same output, 4), so a unique inverse cannot be defined unless the domain is first restricted (e.g. to x≥0), making the function one-to-one.", "hint": "Think about whether you could always uniquely determine the original input, just from knowing the output of x²."}, {"id": "srm124013", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Composite Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "If f(x) = x³ and g(x) = x + 1, what is f(g(2))?", "options": ["8", "9", "27", "28"], "answer": 2, "exp": "Step 1: g(2) = 2+1 = 3. Step 2: f(3) = 3³ = 27.", "hint": "Work out g(2) first, then substitute that result into f(x)."}, {"id": "srm124014", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Binomial Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "A quality control process finds that 5% of items produced are defective. Using a binomial distribution with n=20 items, what is the expected number of defective items?", "options": ["1", "2", "5", "10"], "answer": 0, "exp": "E(X) = n×p = 20×0.05 = 1.", "hint": "Use the formula E(X) = n × p."}, {"id": "srm124015", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Normal Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Which best describes the standard normal distribution?", "options": ["a normal distribution with any mean and standard deviation", "a specific normal distribution with a mean of 0 and a standard deviation of 1, often used as a reference for z-scores", "a distribution that only applies to discrete data", "a synonym for the binomial distribution"], "answer": 1, "exp": "The standard normal distribution is a specific normal distribution with a mean of 0 and a standard deviation of 1, commonly used as a reference distribution for calculating z-scores and probabilities.", "hint": "Think about the specific, standardised version of the normal distribution, with fixed mean and standard deviation values."}, {"id": "srm124016", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Composite Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "If f(x) = √x (for x ≥ 0) and g(x) = x − 4, what is the domain restriction needed for f(g(x)) = √(x−4) to be defined (over the real numbers)?", "options": ["x ≥ 0", "x ≥ 4", "x ≤ 4", "there is no restriction needed"], "answer": 1, "exp": "Since the expression under the square root (x−4) must be non-negative for a real result, we need x−4≥0, giving x≥4.", "hint": "Think about what value of x ensures the expression inside the square root stays non-negative."}, {"id": "srm124017", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Composite Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "For h(x) = (3x − 1)², which two simpler functions could be combined (using composition) to form h(x)?", "options": ["f(x)=x² and g(x)=3x−1, where h(x)=f(g(x))", "f(x)=3x−1 and g(x)=x, with no real composition involved", "f(x)=x and g(x)=(3x-1)², which is trivial", "h(x) cannot be expressed as a composite function"], "answer": 0, "exp": "h(x) can be expressed as f(g(x)), where g(x)=3x−1 (the inner function) and f(x)=x² (the outer squaring function), since f(g(x))=(3x−1)².", "hint": "Think about identifying an 'inner' function and an 'outer' function that, combined, recreate the original expression."}, {"id": "srm124018", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Composite Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Which best describes why understanding composite functions is useful when applying the chain rule in calculus?", "options": ["composite functions have no connection to the chain rule", "the chain rule is specifically designed to differentiate composite functions, by working with the 'inner' and 'outer' functions separately", "the chain rule only applies to functions that are NOT composite", "composite functions can never be differentiated"], "answer": 1, "exp": "The chain rule is specifically designed to differentiate composite functions, by separately considering the derivative of the 'outer' function and the 'inner' function, then combining them — recognising a function as composite is the first step in applying this rule.", "hint": "Think back to how the chain rule required identifying an 'inner' and 'outer' function, just like composite function notation does."}, {"id": "srm124019", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Binomial Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "A factory's defect rate is modelled by a binomial distribution. If n=50 and the expected number of defects is 5, what is the probability of success (defect), p?", "options": ["0.05", "0.1", "0.5", "5"], "answer": 1, "exp": "Step 1: E(X)=n×p, so 5=50×p. Step 2: p=5/50=0.1.", "hint": "Rearrange the formula E(X)=n×p to solve for p."}, {"id": "srm124020", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Continuous Distributions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Which best describes a 'probability density function' for a continuous random variable, such as one following a normal distribution?", "options": ["a function listing the exact probability of each individual specific value", "a function describing the relative likelihood of values, where probability for a range is found by calculating the AREA under the curve over that range", "a synonym for a discrete probability distribution", "a function that only applies to binomial distributions"], "answer": 1, "exp": "For a continuous random variable, a probability density function describes the relative likelihood of values, with the actual probability for any given range found by calculating the area under the curve over that specific range (since the probability of any single exact value is technically zero).", "hint": "Think about why, for continuous data, you need to look at probability across a RANGE of values, rather than a single exact point."}, {"id": "srm124021", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Composite Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "If f(x) = 1/x (for x ≠ 0), what is f(f(x))?", "options": ["x", "1/x", "x²", "1"], "answer": 0, "exp": "Step 1: f(f(x)) means substituting f(x) into itself: f(1/x) = 1/(1/x) = x.", "hint": "Substitute 1/x into the function f(x)=1/x itself, and simplify."}, {"id": "srm124022", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Inverse Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Which best describes why f(x) = 1/x (from the previous question) is described as 'self-inverse' (or an involution)?", "options": ["this function has no real inverse at all", "applying the function to itself twice returns the original input, meaning the function is its own inverse", "this function always returns zero", "self-inverse functions cannot be composed with themselves"], "answer": 1, "exp": "Since applying f(x)=1/x to itself returns the original input (f(f(x))=x), this function is described as 'self-inverse' (an involution) — it is literally its own inverse function.", "hint": "Think about what it means for a function, when composed with itself, to simply return the original value."}, {"id": "srm124023", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Binomial Distribution", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "A binomial distribution has n=15 and p=0.4. What is the standard deviation of this distribution, to 2 decimal places? (Use SD = √(Var(X)) = √(n×p×(1−p)).)", "options": ["1.90", "3.60", "6.00", "9.00"], "answer": 0, "exp": "Step 1: Var(X) = 15×0.4×0.6 = 3.6. Step 2: SD = √3.6 ≈ 1.90.", "hint": "Calculate the variance first using n×p×(1−p), then take the square root."}, {"id": "srm124024", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Probability — Applications", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "Which best describes why probability distributions (such as the binomial or normal distribution) are useful tools in statistics and decision-making?", "options": ["probability distributions have no real practical application", "they provide a mathematical model for predicting the likelihood of different outcomes, supporting informed decisions under uncertainty", "probability distributions can only be used in pure mathematics, never real-world contexts", "every real-world scenario follows exactly the same probability distribution"], "answer": 1, "exp": "Probability distributions provide a mathematical model for predicting the likelihood of different outcomes (such as the number of defective items, or a measurement's likely range), supporting informed decisions under genuine uncertainty in fields from quality control to medicine.", "hint": "Think about how having a mathematical MODEL for uncertain outcomes could support better decision-making."}, {"id": "srm124025", "state": "AU", "section": "sr_methods", "grade": "12", "topic": "Functions — Composite and Inverse Functions", "difficulty": "hard", "style": "standard", "paper": "G12-M4", "q": "If f(x) = x + 5 and g(x) = 3x, what is f⁻¹(g(4))?", "options": ["7", "12", "17", "19"], "answer": 0, "exp": "Step 1: g(4) = 3×4 = 12. Step 2: f⁻¹(x) = x − 5 (since f(x)=x+5). Step 3: f⁻¹(12) = 12 − 5 = 7.", "hint": "Work out g(4) first, then find the rule for f⁻¹(x) and apply it to that result."}];